def evaluate_scope(project):
    is_good = (
        project["problem_clear"]
        and project["has_test_plan"]
        and project["features"] <= 4
    )

    if is_good:
        scope = "good"
        if project["uses_files"]:
            next_step = "Build the smallest file-based version first."
        else:
            next_step = "Build the smallest working version first."
    else:
        scope = "too_big"
        next_step = "Cut features and define a simple test plan."

    return {
        "name": project["name"],
        "scope": scope,
        "next_step": next_step,
    }
